import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess }) => {
  const [clients, setClients] = useState([]);
  const [articles, setArticles] = useState([]);
  const [formData, setFormData] = useState({
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });
  const [message, setMessage] = useState('');
  const [isError, setIsError] = useState(false);

  // Chargement clients et articles
  useEffect(() => {
    fetch('http://localhost:3001/clients')
      .then(res => res.json())
      .then(data => setClients(data))
      .catch(() => setClients([]));

    fetch('http://localhost:3001/articles')
      .then(res => res.json())
      .then(data => setArticles(data))
      .catch(() => setArticles([]));
  }, []);

  // Remplir le formulaire si modification
  useEffect(() => {
    if (selectedCommande) {
      setFormData(selectedCommande);
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const resetForm = () => {
    setFormData({
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
    setMessage('');
    setIsError(false);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Validation simple quantité
    const qty = Number(formData.QteCom);
    if (isNaN(qty) || qty <= 0) {
      setMessage('La quantité doit être un nombre positif');
      setIsError(true);
      return;
    }

    try {
      const method = selectedCommande ? 'PUT' : 'POST';
      // Si modification, on utilise l'ID de la commande (par exemple codeCom)
      const url = selectedCommande
        ? `http://localhost:3001/commandes/${selectedCommande.codeCom}`
        : 'http://localhost:3001/commandes';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      const data = await res.json();
      setMessage(data.message || (selectedCommande ? 'Commande modifiée' : 'Commande ajoutée'));
      setIsError(false);

      if (!selectedCommande) resetForm();
      if (onSuccess) onSuccess();

      setTimeout(() => setMessage(''), 4000);
    } catch (err) {
      setMessage(err.message);
      setIsError(true);
    }
  };

  // Suppression (optionnelle)
  const handleDelete = async () => {
    if (!selectedCommande) return;

    if (!window.confirm('Supprimer cette commande ?')) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${selectedCommande.codeCom}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setMessage(err.message);
      setIsError(true);
    }
  };

  return (
    <div className="commande-form">
      <h2>{selectedCommande ? 'Modifier la Commande' : 'Ajouter une Commande'}</h2>
      {message && (
        <p className={isError ? 'error-message' : 'success-message'}>{message}</p>
      )}
      <form onSubmit={handleSubmit}>
        <label>Client :</label>
        <select name="codeCli" value={formData.codeCli} onChange={handleChange} required>
          <option value="">-- Choisir un client --</option>
          {clients.map(c => (
            <option key={c.codeCli} value={c.codeCli}>
              {c.nomCli} {c.prenomCli}
            </option>
          ))}
        </select>

        <label>Article :</label>
        <select name="codeArt" value={formData.codeArt} onChange={handleChange} required>
          <option value="">-- Choisir un article --</option>
          {articles.map(a => (
            <option key={a.codeArt} value={a.codeArt}>
              {a.nomArt}
            </option>
          ))}
        </select>

        <label>Date :</label>
        <input type="date" name="dateCom" value={formData.dateCom} onChange={handleChange} required />

        <label>Quantité :</label>
        <input type="number" name="QteCom" value={formData.QteCom} onChange={handleChange} min="1" required />

        <button type="submit">{selectedCommande ? 'Modifier' : 'Ajouter'}</button>
        {selectedCommande && (
          <button type="button" onClick={handleDelete} style={{ marginLeft: '10px', backgroundColor: 'red', color: 'white' }}>
            Supprimer
          </button>
        )}
      </form>
    </div>
  );
};

export default CommandeForm;
